import json
from typing import Dict, Any, List
import re

class JSONMode:
    """Generate structured JSON outputs from LLMs"""

    def __init__(self):
        pass

    def enforce_schema(self, text: str, schema: Dict) -> Dict:
        """Extract data matching schema from text"""
        # Simulate LLM extraction
        extracted = {}

        for field, field_info in schema["properties"].items():
            field_type = field_info.get("type")
            pattern = field_info.get("pattern", r"\S+")

            # Simple extraction simulation
            if field in text.lower():
                if field_type == "string":
                    # Extract word after field
                    match = re.search(f"{field}[:\s]+(\S+)", text, re.IGNORECASE)
                    extracted[field] = match.group(1) if match else None
                elif field_type == "number":
                    match = re.search(f"{field}[:\s]+(\d+)", text, re.IGNORECASE)
                    extracted[field] = int(match.group(1)) if match else None
                elif field_type == "array":
                    extracted[field] = []

        return extracted

    def function_calling_format(self, function_name: str, arguments: Dict) -> str:
        """Format output for function calling"""
        return json.dumps({
            "name": function_name,
            "arguments": arguments
        })

    def extract_with_schema(self, text: str, schema: Dict) -> Dict:
        """Extract data following JSON schema"""
        prompt = f"""Extract the following information as JSON following this schema:
{json.dumps(schema, indent=2)}

Text: {text}

Output JSON:"""

        # Simulated extraction
        result = {}
        for field in schema.get("required", []):
            if field == "name":
                result["name"] = "John Doe"
            elif field == "email":
                result["email"] = "john@example.com"
            elif field == "items":
                result["items"] = ["item1", "item2"]
            elif field == "price":
                result["price"] = 99.99

        return result

class StructuredOutputGenerator:
    """Generate structured outputs with validation"""

    def __init__(self):
        self.json_mode = JSONMode()

    def generate_recipe(self, text: str) -> Dict:
        """Generate recipe JSON from text"""
        schema = {
            "type": "object",
            "properties": {
                "name": {"type": "string"},
                "ingredients": {"type": "array", "items": {"type": "string"}},
                "steps": {"type": "array", "items": {"type": "string"}},
                "prep_time": {"type": "number"},
                "cook_time": {"type": "number"},
                "servings": {"type": "number"}
            },
            "required": ["name", "ingredients", "steps"]
        }

        # Simulate extraction
        return {
            "name": "Pasta Carbonara",
            "ingredients": ["pasta", "eggs", "pecorino", "guanciale", "black pepper"],
            "steps": [
                "Cook pasta in salted water",
                "Fry guanciale until crispy",
                "Mix eggs and cheese",
                "Combine everything with pasta water",
                "Season with pepper"
            ],
            "prep_time": 10,
            "cook_time": 15,
            "servings": 4
        }

    def generate_customer_record(self, text: str) -> Dict:
        """Extract customer information"""
        schema = {
            "type": "object",
            "properties": {
                "customer_id": {"type": "string", "pattern": "^CUST-\\d+$"},
                "name": {"type": "string"},
                "email": {"type": "string", "format": "email"},
                "order_total": {"type": "number", "minimum": 0},
                "items": {"type": "array"}
            }
        }

        return self.json_mode.extract_with_schema(text, schema)

